sys_ws_operation.operation_script:
(function process(request, response) {
  var utils = new AlationUtils();


  var qs = request.queryParams || {};
  var catInput = (qs.category || '').toString().trim();
  if (!catInput) return utils.error(response, 400, 'category is required');

  var qRaw = (qs.q || '').toString();
  var q = qRaw ? qRaw.trim().toLowerCase() : '';
  var startAt = parseInt(qs.startAt, 10); if (isNaN(startAt) || startAt < 0) startAt = 0;
  var maxResults = parseInt(qs.maxResults, 10); if (isNaN(maxResults) || maxResults < 1) maxResults = 25;
  if (maxResults > 100) maxResults = 100;

  var lang = gs.getSession().getLanguage() || 'en';

  // Resolve category to its *value* (match by exact value or case-insensitive label)
  var catValue = null, catLabel = null;

  var cat = new GlideRecord('sys_choice');
  cat.addQuery('name', 'incident');
  cat.addQuery('element', 'category');
  cat.addQuery('inactive', false);
  cat.addQuery('language', lang);
  cat.orderBy('sequence');
  cat.orderBy('label');
  cat.query();

  var catInputLower = catInput.toLowerCase();
  while (cat.next()) {
    var cv = String(cat.value || '');
    var cl = String(cat.label || cv);
    if (cv === catInput || cl.toLowerCase() === catInputLower) {
      catValue = cv;
      catLabel = cl;
      break;
    }
  }

  if (!catValue) {
    return utils.error(response, 404, 'category not found');
  }

  // Fetch subcategories where dependent_value == catValue
  var sc = new GlideRecord('sys_choice');
  sc.addQuery('name', 'incident');
  sc.addQuery('element', 'subcategory');
  sc.addQuery('inactive', false);
  sc.addQuery('language', lang);
  sc.addQuery('dependent_value', catValue);
  sc.orderBy('sequence');
  sc.orderBy('label');
  sc.query();

  var results = [];
  var seen = 0;
  while (sc.next()) {
    var value = String(sc.value || '');
    var label = String(sc.label || value);
    if (q) {
      var hay = (label + ' ' + value).toLowerCase();
      if (hay.indexOf(q) === -1) continue;
    }
    if (seen++ < startAt) continue;
    results.push({ value: value, label: label });
    if (results.length >= maxResults) break;
  }

  var nextStartAt = results.length === maxResults ? (startAt + results.length) : null;

  return utils.ok(response, 200, {
    category: { value: catValue, label: catLabel },
    startAt: startAt,
    maxResults: maxResults,
    nextStartAt: nextStartAt,
    results: results
  });
})(request, response);
